import{_ as e,o as r,c as o,ag as a}from"./chunks/framework.OsDJF_Ea.js";const i="/docs/modules/audio-recorder.png",p=JSON.parse('{"title":"Audio Recorder","description":"","frontmatter":{},"headers":[],"relativePath":"modules/audio-recorder.md","filePath":"modules/audio-recorder.md"}'),d={name:"modules/audio-recorder.md"};function n(s,t,l,c,g,u){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="audio-recorder" tabindex="-1">Audio Recorder <a class="header-anchor" href="#audio-recorder" aria-label="Permalink to &quot;Audio Recorder&quot;">​</a></h1><p><strong>Category:</strong> Granular / Looping</p><p>Records and plays back audio files to and from the SD card. Two complementary modes:</p><ul><li><strong>Recording</strong> -- captures live audio from the input straight to SD as WAV files. Buttons or CV gates start and stop the recorder; filenames auto-increment so each take is preserved.</li><li><strong>Playback</strong> -- loads a folder of WAV files from SD and plays them back. In manual mode the buttons step through files; in <strong>trigger mode</strong> (<code>trigger_mode=1</code>) each rising edge on <code>ar_trigger</code> advances to the next file and plays it -- ideal for installations where a sensor strike should fire the next sound. An in-memory ring buffer streams audio from SD so files can be any length.</li></ul><img src="'+i+'" alt="audio-recorder module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>inL</strong> (audio)</td><td>Left audio to record.</td></tr><tr><td><strong>inR</strong> (audio)</td><td>Right audio to record.</td></tr><tr><td><strong>input_gain</strong></td><td>Input amplification 0-2 (1.0 = unity, 2.0 = +6dB). Boost weak contact mic signals or tame hot line-level sources. CV-controllable.</td></tr><tr><td><strong>monitor_level</strong></td><td>Wet/dry monitor blend 0-1 of the live input to the output. Active in all states (idle, recording, playback). 0 = silent monitoring, 1 = full input bleed.</td></tr><tr><td><strong>record</strong></td><td>Record gate. Rising edge starts recording, falling edge stops. Recordings are saved to SD as <code>{file_prefix}_NNN.wav</code> with auto-incrementing index.</td></tr><tr><td><strong>play</strong></td><td>Play gate. Rising edge starts or pauses playback of the current file.</td></tr><tr><td><strong>prev_file</strong></td><td>Rising edge moves the playback pointer back one file in the playback folder. Wraps from the first file to the last.</td></tr><tr><td><strong>next_file</strong></td><td>Rising edge advances the playback pointer one file in the playback folder. Wraps from the last file to the first.</td></tr><tr><td><strong>ar_trigger</strong></td><td>Round-robin trigger input. Rising edge advances to the next file and plays it. Only active when <code>trigger_mode=1</code>. Recording is disabled in trigger mode to prevent accidental overwrites in installation use.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>outL</strong> (audio)</td><td>Left playback audio (with monitor passthrough).</td></tr><tr><td><strong>outR</strong> (audio)</td><td>Right playback audio.</td></tr><tr><td><strong>recording</strong></td><td>Gate output that goes high while recording is active. Connect to an LED, meter, or VCA to indicate recording state.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>For installations: set playback_folder to a folder of WAV files, set trigger_mode=1, connect PiezoInput trigger output to ar_trigger. Each strike plays the next file. Btn3/4 still navigate manually. Recording is disabled in trigger mode.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',12)])])}const m=e(d,[["render",n]]);export{p as __pageData,m as default};
